import{_ as s,o as a,c as e,a3 as t}from"./chunks/framework.aYYe0dfI.js";const d=JSON.parse('{"title":"clore::extract::normalizeentryfile","description":"The function clore::extract::normalize_entry_file takes a CompileEntry and returns a normalized file path as a std::string. It begins by constructing a std::filesystem::path from entry.file. If the path is relative, it is prefixed with entry.directory. After converting to an absolute path using fs::absolute (with error checking), the path is normalized via lexically_normal(). A subsequent call to fs::weakly_canonical attempts to resolve any symbolic links and produce a canonical path; if this fails (e.g., the file does not exist), the function falls back to the lexically-normalized path. The result is always returned as a generic string (forward slashes).","frontmatter":{"title":"clore::extract::normalizeentryfile","description":"The function clore::extract::normalize_entry_file takes a CompileEntry and returns a normalized file path as a std::string. It begins by constructing a std::filesystem::path from entry.file. If the path is relative, it is prefixed with entry.directory. After converting to an absolute path using fs::absolute (with error checking), the path is normalized via lexically_normal(). A subsequent call to fs::weakly_canonical attempts to resolve any symbolic links and produce a canonical path; if this fails (e.g., the file does not exist), the function falls back to the lexically-normalized path. The result is always returned as a generic string (forward slashes).","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/modules/extract/functions/normalize-entry-file.md","filePath":"en/clore/modules/extract/functions/normalize-entry-file.md"}'),n={name:"clore/modules/extract/functions/normalize-entry-file.md"};function l(h,i,r,p,o,k){return a(),e("div",null,[...i[0]||(i[0]=[t("",17)])])}const E=s(n,[["render",l]]);export{d as __pageData,E as default};
